Here's a JavaScript function to sort numbers in ascending order:

```javascript
function sortNumbers(arr) {
    return arr.slice().sort((a, b) => a - b);
}
```

Important: JavaScript's default `.sort()` converts elements to strings, which gives wrong results for numbers (e.g., [10, 2, 1] becomes [1, 10, 2]). The comparator `(a, b) => a - b` fixes this by comparing numerically. We use `.slice()` first to avoid mutating the original array.

Here's how to create a REST API with FastAPI:

```python
from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    name: str
    price: float
    in_stock: bool = True

# In-memory store
items = {}

@app.get('/items')
def list_items():
    return list(items.values())

@app.get('/items/{item_id}')
def get_item(item_id: int):
    if item_id not in items:
        return {'error': 'Not found'}
    return items[item_id]

@app.post('/items')
def create_item(item: Item):
    item_id = len(items) + 1
    items[item_id] = item.dict()
    return {'id': item_id, **item.dict()}

@app.delete('/items/{item_id}')
def delete_item(item_id: int):
    items.pop(item_id, None)
    return {'deleted': True}
```

Run with `uvicorn main:app --reload`. FastAPI auto-generates interactive docs at `/docs`. Pydantic models handle request validation automatically.

Here's a dynamic programming solution:

```python
def longest_common_subsequence(s1: str, s2: str) -> str:
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Build the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])

    # Backtrack to find the actual subsequence
    result = []
    i, j = m, n
    while i > 0 and j > 0:
        if s1[i-1] == s2[j-1]:
            result.append(s1[i-1])
            i -= 1
            j -= 1
        elif dp[i-1][j] > dp[i][j-1]:
            i -= 1
        else:
            j -= 1

    return ''.join(reversed(result))

# Example
print(longest_common_subsequence('abcde', 'ace'))  # 'ace'
```

Time complexity: O(m*n). Space: O(m*n). This is a classic interview problem that tests understanding of dynamic programming.

Here's a stack implementation in Python:

```python
class Stack:
    def __init__(self):
        self._items = []

    def push(self, item):
        """Add item to the top of the stack."""
        self._items.append(item)

    def pop(self):
        """Remove and return the top item. Raises IndexError if empty."""
        if self.is_empty():
            raise IndexError('pop from empty stack')
        return self._items.pop()

    def peek(self):
        """Return the top item without removing it."""
        if self.is_empty():
            raise IndexError('peek at empty stack')
        return self._items[-1]

    def is_empty(self):
        """Check if the stack is empty."""
        return len(self._items) == 0

    def __len__(self):
        return len(self._items)

    def __repr__(self):
        return f'Stack({self._items})'

# Usage
s = Stack()
s.push(1)
s.push(2)
s.push(3)
print(s.pop())    # 3 (LIFO — last in, first out)
print(s.peek())   # 2
print(len(s))     # 2
```

A stack follows **LIFO** (Last In, First Out). Common uses: undo/redo, browser history, expression evaluation, call stack management, DFS traversal.

Here's a React todo list component:

```jsx
import { useState } from 'react';

export default function TodoList() {
    const [todos, setTodos] = useState([]);
    const [input, setInput] = useState('');

    function addTodo(e) {
        e.preventDefault();
        if (!input.trim()) return;
        setTodos([...todos, { id: Date.now(), text: input, done: false }]);
        setInput('');
    }

    function toggleTodo(id) {
        setTodos(todos.map(t => t.id === id ? { ...t, done: !t.done } : t));
    }

    function deleteTodo(id) {
        setTodos(todos.filter(t => t.id !== id));
    }

    return (
        <div>
            <h1>Todo List</h1>
            <form onSubmit={addTodo}>
                <input
                    value={input}
                    onChange={e => setInput(e.target.value)}
                    placeholder="Add a task..."
                />
                <button type="submit">Add</button>
            </form>
            <ul>
                {todos.map(todo => (
                    <li key={todo.id} style={{ textDecoration: todo.done ? 'line-through' : 'none' }}>
                        <span onClick={() => toggleTodo(todo.id)}>{todo.text}</span>
                        <button onClick={() => deleteTodo(todo.id)}>Delete</button>
                    </li>
                ))}
            </ul>
            <p>{todos.filter(t => !t.done).length} remaining</p>
        </div>
    );
}
```

Uses `useState` for state management, handles form submission, and supports adding, toggling, and deleting todos. Each todo has a unique `id` for React's key prop.

Here's a queue implemented with two stacks:

```python
class QueueFromStacks:
    def __init__(self):
        self._inbox = []   # for enqueue
        self._outbox = []  # for dequeue

    def enqueue(self, item):
        """Add item to the back of the queue."""
        self._inbox.append(item)

    def dequeue(self):
        """Remove and return the front item."""
        if not self._outbox:
            # Transfer all items from inbox to outbox (reverses order)
            while self._inbox:
                self._outbox.append(self._inbox.pop())
        if not self._outbox:
            raise IndexError('dequeue from empty queue')
        return self._outbox.pop()

    def peek(self):
        if not self._outbox:
            while self._inbox:
                self._outbox.append(self._inbox.pop())
        if not self._outbox:
            raise IndexError('peek at empty queue')
        return self._outbox[-1]

    def is_empty(self):
        return not self._inbox and not self._outbox

# Usage: FIFO (First In, First Out)
q = QueueFromStacks()
q.enqueue('a')
q.enqueue('b')
q.enqueue('c')
print(q.dequeue())  # 'a'
print(q.dequeue())  # 'b'
```

**How it works:** Enqueue pushes to inbox. Dequeue pops from outbox. When outbox is empty, transfer all items from inbox (this reverses the order, giving FIFO behavior). Each element is moved at most twice, so amortized time per operation is O(1).

Here's a binary search tree (BST) with insert, search, and in-order traversal:

```python
class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        self.root = self._insert(self.root, val)

    def _insert(self, node, val):
        if not node:
            return TreeNode(val)
        if val < node.val:
            node.left = self._insert(node.left, val)
        elif val > node.val:
            node.right = self._insert(node.right, val)
        return node

    def search(self, val):
        return self._search(self.root, val)

    def _search(self, node, val):
        if not node or node.val == val:
            return node
        if val < node.val:
            return self._search(node.left, val)
        return self._search(node.right, val)

    def inorder(self):
        result = []
        self._inorder(self.root, result)
        return result

    def _inorder(self, node, result):
        if node:
            self._inorder(node.left, result)
            result.append(node.val)
            self._inorder(node.right, result)

# Usage
tree = BST()
for val in [5, 3, 7, 1, 4, 6, 8]:
    tree.insert(val)

print(tree.inorder())      # [1, 3, 4, 5, 6, 7, 8] (sorted!)
print(tree.search(4).val)  # 4
print(tree.search(9))      # None
```

In-order traversal of a BST always produces sorted output. Average time for insert/search is O(log n), worst case O(n) if the tree becomes unbalanced.

Middleware is code that runs between receiving a request and sending a response. It can inspect, modify, or reject requests before they reach your route handler.

**In Express.js:**
```javascript
// Logging middleware
app.use((req, res, next) => {
    console.log(`${req.method} ${req.url} - ${new Date().toISOString()}`);
    next(); // pass to next middleware/route
});

// Auth middleware
function authenticate(req, res, next) {
    const token = req.headers.authorization;
    if (!token) return res.status(401).json({ error: 'No token' });
    req.user = verifyToken(token);
    next();
}

app.get('/api/profile', authenticate, (req, res) => {
    res.json(req.user);
});
```

**In FastAPI (Python):**
```python
from fastapi import Request

@app.middleware('http')
async def log_requests(request: Request, call_next):
    print(f'{request.method} {request.url}')
    response = await call_next(request)
    return response
```

**Common uses:**
- Authentication and authorization
- Request logging
- CORS handling
- Rate limiting
- Error handling
- Response compression
- Request/response transformation

Middleware forms a pipeline — each piece does one thing, then passes to the next. This keeps code modular and reusable.

Here's a trie implementation:

```python
class TrieNode:
    def __init__(self):
        self.children = {}  # char -> TrieNode
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def search(self, word: str) -> bool:
        node = self._find(word)
        return node is not None and node.is_end

    def starts_with(self, prefix: str) -> bool:
        return self._find(prefix) is not None

    def _find(self, prefix: str):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def autocomplete(self, prefix: str) -> list:
        """Return all words that start with prefix."""
        node = self._find(prefix)
        if not node:
            return []
        results = []
        self._collect(node, prefix, results)
        return results

    def _collect(self, node, current, results):
        if node.is_end:
            results.append(current)
        for char, child in node.children.items():
            self._collect(child, current + char, results)

# Usage
t = Trie()
for word in ['apple', 'app', 'application', 'apt', 'banana', 'band']:
    t.insert(word)

print(t.search('app'))        # True
print(t.search('ap'))         # False (not a complete word)
print(t.starts_with('ap'))    # True
print(t.autocomplete('app'))  # ['app', 'apple', 'application']
print(t.autocomplete('ba'))   # ['banana', 'band']
```

Tries are used in autocomplete, spell checkers, IP routing, and word games. Insert and search are O(m) where m is word length — independent of how many words are stored.
